package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }
import ssg.js.compress.{ InlineLevel }

final class CompressManglepropsKeyAnnotationSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // key_annotation_negative_case
  // =========================================================================
  test("key_annotation_negative_case".fail) {
    assertCompresses(
      input = """function lookup(object, key) {
            return object[key];
        }
        lookup({ someprop: "bar" }, "someprop")""".stripMargin.trim,
      expected = """function lookup(o, p) {
            return o[p];
        }
        lookup({ o: "bar" }, "someprop")""".stripMargin.trim,
      options = AllOff.copy(
        inline = InlineLevel.InlineDisabled
      )
    )
  }

  // =========================================================================
  // key_annotation_basic_use
  // =========================================================================
  test("key_annotation_basic_use".fail) {
    assertCompresses(
      input = """function lookup(object, key) {
            return object[key];
        }
        lookup({ someprop: "bar" }, /*@__KEY__*/ "someprop")""".stripMargin.trim,
      expected = """function lookup(o,p){
            return o[p]
        }
        lookup({o:"bar"},"o")""".stripMargin.trim,
      options = AllOff.copy(
        inline = InlineLevel.InlineDisabled
      )
    )
  }

  // =========================================================================
  // key_annotation_in_operator
  // =========================================================================
  test("key_annotation_in_operator".fail) {
    assertCompresses(
      input = """const object = { someprop: "bar", o: true}
        "someprop" in object;
        /*@__KEY__*/ "someprop" in object""".stripMargin.trim,
      expected = """const object={o:"bar", p : true};
        "o"in object;
        "o"in object""".stripMargin.trim,
      options = AllOff.copy(
        inline = InlineLevel.InlineDisabled
      )
    )
  }

  // =========================================================================
  // key_annotation_in_operator_tricky_case
  // =========================================================================
  test("key_annotation_in_operator_tricky_case".fail) {
    assertCompresses(
      input = """// By default someprop mangles to "o", add key "o" to try and trip up the mangler
        const object = { someprop: "bar", o: true}
        "someprop" in object;
        /*@__KEY__*/ "someprop" in object""".stripMargin.trim,
      expected = """const object={o:"bar", p: true};
        "o"in object;
        "o"in object""".stripMargin.trim,
      options = AllOff.copy(
        inline = InlineLevel.InlineDisabled
      )
    )
  }

}
